import xml.etree.ElementTree as ET

def parse_xml_config(file_path):
    tree = ET.parse(file_path, parser=ET.XMLParser(entity_factory=None))
    root = tree.getroot()
    settings = {}
    for child in root:
        settings[child.tag] = child.text.strip() if child.text else None
    return settings